const allInputs = $input.all();
const moviesMap = {};

allInputs.forEach(input => {
  const cinemaName = input.json.cinema;
  const films = input.json.films || [];

  films.forEach(film => {
    const title = film.titre;

    if (!moviesMap[title]) {
      moviesMap[title] = {
        titre: title,
        duree: film.duree,
        affiche: film.affiche,
        seances: {} 
      };
    }

    let key = "UGC";
    if (cinemaName.includes("Vox")) key = "Vox";
    if (cinemaName.includes("Cosmos")) key = "Le Cosmos";
    if (cinemaName.includes("Star SE")) key = "Star St-Exupéry";
    else if (cinemaName.includes("Star")) key = "Star";

    moviesMap[title].seances[key] = film.horaires;
  });
});

const sortedMovies = Object.values(moviesMap).sort((a, b) => a.titre.localeCompare(b.titre));

return [{ json: { liste_films: sortedMovies } }];

const baseUrl = "https://www.allocine.fr/_/showtimes/theater-P0025/d-";
const formattedDate = $input.first().json['formatted-url']
return [{
  json: {
    StarSEUrl: baseUrl + formattedDate
  }
}];

const results = $input.first().json.results || [];
const nomDuCinema = "Star SE";
const now = new Date();

const simplifiedData = results.map(item => {
  const st = item.showtimes;
  if (!st) return null;

  let allShowtimes = [];

  Object.keys(st).forEach(key => {
    const list = st[key];
    if (Array.isArray(list)) {
      list.forEach(s => {
        const date = new Date(s.startsAt);
        if (date < now) return; 

        const heure = date.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });

        allShowtimes.push({
          time: heure,
          rawTime: s.startsAt,
          isVost: s.diffusionVersion === "ORIGINAL",
          isPreview: !!s.isPreview
        });
      });
    }
  });

  if (allShowtimes.length === 0) return null;
  allShowtimes.sort((a, b) => a.rawTime.localeCompare(b.rawTime));

  return {
    titre: item.movie?.title?.toUpperCase().replace(/["«»]/g, '').trim() || "FILM INCONNU",
    duree: item.movie?.runtime || 0,
    affiche: item.movie?.poster?.url || "",
    horaires: allShowtimes
  };
}).filter(film => film !== null);

return [{ json: { cinema: nomDuCinema, films: simplifiedData } }];

